// // This module decrements an 8-bit output on every rising edge of the clock signal. When the reset signal is asserted, the output is set to zero.
module top_module( out, clk, reset );output [7:0] out;
    input clk, reset;
    reg [7:0] out;

    always @(posedge clk, posedge reset)
      if (reset)
          out <= 8'b0;
      else
          out <= out + 1;
endmodule
